args.ReplacementContent:
"            <div className="flex -mx-6 bg-transparent px-6">
              {[
                { id: 'active', label: 'ATIVAS', count: activeJobsCount, icon: Briefcase },
                { id: 'paused', label: 'PAUSADAS', count: pausedJobsCount, icon: Clock },
                { id: 'closed', label: 'ENCERRADAS', count: closedJobsCount, icon: XCircle }
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setJobSubTab(tab.id as any)}
                  className={`flex items-center gap-2 px-6 py-4 border-b-2 font-bold text-xs uppercase tracking-wider transition-all relative ${
                    jobSubTab === tab.id 
                      ? 'border-[#533af6] text-slate-900 font-extrabold' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <tab.icon size={14} className={jobSubTab === tab.id ? 'text-[#533af6]' : 'text-slate-400'} />
                  <span>{tab.label} ({tab.count})</span>
                  {jobSubTab === tab.id && (
                    <motion.div 
                      layoutId="activeJobSubTabUnderline"
                      className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#533af6]"
                      transition={{ type: 'spring', stiffness: 120, damping: 22, opacity: { duration: 0 } }}
                    />
                  )}
                </button>
              ))}"

